import type { FC } from 'react';
import React, { useEffect, useMemo, useState } from 'react';
import clsx from 'clsx';
import clamp from 'lodash/clamp';
import { useCssScope } from '../../config-provider/hooks';
import { HrgbKey } from '../type';
import NativeInput from '../../shared/components/Input';

interface ColorInputProps {
  color: number | string;
  colorKey: HrgbKey;
  onChange: (key: HrgbKey, val: string | number) => void;
  prefixCls?: string;
}

export const ColorInput: FC<ColorInputProps> = props => {
  const { colorKey, color, onChange, prefixCls } = props;
  const [value, setValue] = useState(color);
  const cssScope = useCssScope('color-picker-input');
  const prefix = prefixCls || cssScope();

  useEffect(() => {
    setValue(color);
  }, [color]);

  const colorVal = useMemo(() => `${value}`.toUpperCase(), [value]);

  const handleChange = (e: any) => {
    setValue(e.target.value);
  };

  const judgeVal = (key: HrgbKey) => {
    const val = value.toString();
    if (key !== HrgbKey.HEX) {
      if (/^-?[0-9]+\.?[0-9]*$/.test(val)) {
        // eslint-disable-next-line @typescript-eslint/no-magic-numbers
        return clamp(parseInt(val, 10), 0, 255);
      }
      return color;
    } else {
      const hexRegex = /^#?([0-9A-Fa-f]{0,6})$/;
      const matchGroup = hexRegex.exec(val);
      if (!matchGroup) {
        return color.toString().toUpperCase();
      }
      const colorStr = matchGroup[1].toUpperCase();
      const len = colorStr.length;
      if (len !== 3) {
        return colorStr + '0'.repeat(6 - len);
      } else {
        let newVal = '';
        for (let i = 0; i < len; i++) {
          newVal += colorStr[i].repeat(2);
        }
        return newVal;
      }
    }
  };

  const handleBlur = (key: HrgbKey) => {
    try {
      const newVal = judgeVal(key);
      setValue(newVal);
      onChange && onChange(key, newVal);
    } catch (err) {
      /* empty */
    }
  };

  const handeKeyUp = (e: React.KeyboardEvent, key: HrgbKey) => {
    // eslint-disable-next-line @typescript-eslint/no-magic-numbers
    if (e.keyCode === 13) {
      handleBlur(key);
    }
  };

  return (
    <div className={clsx(prefix, colorKey === HrgbKey.HEX && `${prefix}-hex`)}>
      <span className={`${prefix}-title`}>{colorKey.toUpperCase()}</span>
      <div className={`${prefix}-outer`}>
        <NativeInput
          type="text"
          className={`${prefix}-inner`}
          value={colorVal}
          onChange={handleChange}
          onBlur={() => handleBlur(colorKey)}
          onKeyUp={e => handeKeyUp(e, colorKey)}
        />
      </div>
    </div>
  );
};
